mapper.select:
SELECT SCHEDULE_SN AS scheduleSn, SCHEDULE_NM AS scheduleNm, SCHEDULE_CN AS scheduleCn, SCHEDULE_ADRES AS scheduleAdres, TO_CHAR(SCHEDULE_START_DE, 'YYYY-MM-DD') AS scheduleStartDe, TO_CHAR(SCHEDULE_END_DE, 'YYYY-MM-DD') AS scheduleEndDe, T.LOC_GEOM.SDO_POINT.X AS locLon, T.LOC_GEOM.SDO_POINT.Y AS locLat FROM ( SELECT SCHEDULE_SN, SCHEDULE_NM, SCHEDULE_CN, SCHEDULE_START_DE, SCHEDULE_END_DE, SCHEDULE_ADRES, CASE WHEN LOC_GEOM IS NOT NULL THEN SDO_CS.TRANSFORM(LOC_GEOM, 4326) ELSE NULL END AS LOC_GEOM FROM TB_SCHEDULE WHERE LOC_GEOM IS NOT NULL
AND ( TO_CHAR(SCHEDULE_START_DE, 'YYYY-MM') = #{searchMonth} OR TO_CHAR(SCHEDULE_END_DE, 'YYYY-MM') = #{searchMonth} OR (SCHEDULE_START_DE < TO_DATE(#{searchMonth} || '-01', 'YYYY-MM-DD') AND SCHEDULE_END_DE >= TO_DATE(#{searchMonth} || '-01', 'YYYY-MM-DD')) )
) T

SELECT COUNT(*) 
FROM USER_INFO
WHERE USR_ID = #{usrId}
